import{_ as o,o as t,c as n,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"ADR-001: Hotel là Content Reference vĩnh viễn (Phase 1 + Phase 2)","description":"","frontmatter":{},"headers":[],"relativePath":"02-kien-truc/decisions/ADR-001-hotel-content-reference.md","filePath":"02-kien-truc/decisions/ADR-001-hotel-content-reference.md"}'),a={name:"02-kien-truc/decisions/ADR-001-hotel-content-reference.md"};function l(h,e,r,c,u,s){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-001-hotel-la-content-reference-vinh-vien-phase-1-phase-2" tabindex="-1">ADR-001: Hotel là Content Reference vĩnh viễn (Phase 1 + Phase 2) <a class="header-anchor" href="#adr-001-hotel-la-content-reference-vinh-vien-phase-1-phase-2" aria-label="Permalink to &quot;ADR-001: Hotel là Content Reference vĩnh viễn (Phase 1 + Phase 2)&quot;">​</a></h1><ul><li><strong>Status</strong>: Accepted</li><li><strong>Ngày</strong>: 2026-05-26</li><li><strong>Người duyệt</strong>: Founder</li></ul><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Trong design ban đầu schema có model <code>HotelBooking</code> + enum <code>BookingType</code> (HOTEL | TOUR), implies Vivu sẽ mở &quot;hotel booking độc lập&quot; như Agoda/Booking ở Phase 2.</p><p>Sau khi user thảo luận về use case &quot;công ty 40 người&quot; + risk scope creep, nhận ra:</p><ul><li>Vivu là <strong>tour operator</strong>, không phải OTA hotel.</li><li>Build hotel booking độc lập sẽ kéo theo: hotel portal cho partner, inventory per-date, calendar UI, refund policy hotel, channel manager — toàn bộ stack riêng.</li><li>Khách Vivu đến để &quot;đi du lịch trọn gói&quot;, không phải &quot;tìm hotel&quot; — sai persona.</li><li>Đối thủ phân khúc này (Agoda, Booking) đã quá mạnh, Vivu không có lợi thế.</li></ul><hr><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Hotel chỉ là content reference trong tour package, không bao giờ bookable độc lập — cả Phase 1 lẫn Phase 2.</strong></p><p>Cụ thể:</p><ol><li>DROP model <code>HotelBooking</code> khỏi schema (YAGNI)</li><li>DROP enum <code>BookingType</code> khỏi schema</li><li>DROP <code>Booking.bookingType</code>, <code>Booking.checkIn</code>, <code>Booking.checkOut</code> cột</li><li><code>Booking + TourBooking</code> luôn 1:1 — không discriminator</li><li>Hotel info gắn vào tour qua <code>TourItinerary.hotelId</code> (per day) + <code>TourItinerary.roomTypeNote</code> (free-text)</li><li>Track allotment qua <code>HotelAllotment</code> monthly (admin nhập tay), không per-date</li><li>Hotel có trang public <code>/hotels/[slug]</code> chỉ để hiển thị info (gallery, amenities, location) — không có nút &quot;Book&quot;</li></ol><p>→ Migration: <code>../../03-co-so-du-lieu/migrations/2026-05-27_add_pricing_options_and_allotment.md</code> PART 8.</p><hr><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="tot" tabindex="-1">Tốt <a class="header-anchor" href="#tot" aria-label="Permalink to &quot;Tốt&quot;">​</a></h3><ul><li>Schema gọn hơn: 21 bảng → 20 bảng</li><li>UX khách hàng đơn giản hơn (không confuse &quot;book tour&quot; vs &quot;book hotel&quot;)</li><li>Brand Vivu rõ ràng: &quot;tour operator&quot;, không loãng</li><li>Phase 2 không phải migrate lại schema vì đã commit vĩnh viễn</li><li>Polymorphic giảm từ 3 chỗ (Booking + Review + SeoPage) còn 2 (Review + SeoPage)</li></ul><h3 id="trade-off" tabindex="-1">Trade-off <a class="header-anchor" href="#trade-off" aria-label="Permalink to &quot;Trade-off&quot;">​</a></h3><ul><li>Mất khả năng &quot;hotel-only revenue&quot; — không vào được phân khúc OTA hotel</li><li>Khách muốn book chỉ hotel sẽ phải dùng đối thủ → mất 1 phần market share</li><li>Phase 3+ nếu pivot model thì migrate đắt (đã accept vì xác suất pivot thấp)</li></ul><h3 id="he-qua-ky-thuat" tabindex="-1">Hệ quả kỹ thuật <a class="header-anchor" href="#he-qua-ky-thuat" aria-label="Permalink to &quot;Hệ quả kỹ thuật&quot;">​</a></h3><ul><li>Hotel page <code>/hotels/[slug]</code> không có booking widget — chỉ gallery + amenities + tour list &quot;Tour có ghé hotel này&quot;</li><li>Admin Hotel CMS focus vào content + allotment, không có booking management</li><li><code>Review</code> vẫn polymorphic 2 nhánh (Hotel | Tour) — vì khách review hotel đã ở trong tour, không phải book riêng</li></ul><hr><h2 id="alternatives-đa-can-nhac" tabindex="-1">Alternatives đã cân nhắc <a class="header-anchor" href="#alternatives-đa-can-nhac" aria-label="Permalink to &quot;Alternatives đã cân nhắc&quot;">​</a></h2><h3 id="a-giu-hotelbooking-cho-phase-2-rejected" tabindex="-1">A. Giữ <code>HotelBooking</code> cho Phase 2 (rejected) <a class="header-anchor" href="#a-giu-hotelbooking-cho-phase-2-rejected" aria-label="Permalink to &quot;A. Giữ `HotelBooking` cho Phase 2 (rejected)&quot;">​</a></h3><ul><li>Phải duy trì schema không dùng → tech debt</li><li>Build Phase 1 phức tạp hơn vì phải nghĩ Phase 2</li></ul><h3 id="b-hotel-request-to-book-—-submit-form-nhu-inquiryrequest-rejected" tabindex="-1">B. Hotel &quot;request to book&quot; — submit form như InquiryRequest (rejected) <a class="header-anchor" href="#b-hotel-request-to-book-—-submit-form-nhu-inquiryrequest-rejected" aria-label="Permalink to &quot;B. Hotel &quot;request to book&quot; — submit form như InquiryRequest (rejected)&quot;">​</a></h3><ul><li>Vẫn confuse persona — Vivu không có capacity vận hành hotel booking</li><li>Trùng với <code>InquiryRequest</code> flow</li></ul><h3 id="c-vivu-thanh-ota-hotel-o-phase-3-rejected" tabindex="-1">C. Vivu thành OTA hotel ở Phase 3 (rejected) <a class="header-anchor" href="#c-vivu-thanh-ota-hotel-o-phase-3-rejected" aria-label="Permalink to &quot;C. Vivu thành OTA hotel ở Phase 3 (rejected)&quot;">​</a></h3><ul><li>Lệch core competency</li><li>Đối thủ quá mạnh phân khúc này</li></ul><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Vision: <code>../../00-san-pham/01-tam-nhin.md</code> mục Non-Goals</li><li>BR-PR (pricing): <code>../../01-nghiep-vu/02-quy-tac-nghiep-vu.md</code></li><li>Migration: <code>../../03-co-so-du-lieu/migrations/2026-05-27_add_pricing_options_and_allotment.md</code> PART 8</li><li>Anchor cũ trace: V-01, V-05 (vĩnh viễn)</li></ul>',32)])])}const k=o(a,[["render",l]]);export{g as __pageData,k as default};
